import base64, hashlib, os, sys, zlib

base = os.path.join("C:" + os.sep + "dev" + os.sep + "trading-automation-system" + os.sep + "trading-platform", "risk_guard")

FM = ""
FM_MD5 = "3c2f15233a0d32edb1c94b91e673afa5"

G = ""
G_MD5 = "5f4e3a5324e901ce1c22481b48337db0"

for name, b64, md5 in [("feed_monitor.py", FM, FM_MD5), ("guard.py", G, G_MD5)]:
    data = zlib.decompress(base64.b64decode(b64))
    actual = hashlib.md5(data).hexdigest()
    if actual != md5:
        print(f"[FAIL] {name} hash mismatch")
        sys.exit(1)
    with open(os.path.join(base, name), "wb") as f:
        f.write(data)
    print(f"[OK] {name} ({len(data)} bytes)")

print("DONE - run: python main.py --mode v3")